# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, request, url_for, session, flash
import requests

app = Flask(__name__)
app.secret_key = "secret_key"

# OpenID Connect configuration (replace with your provider's)
OPENID_CONNECT_AUTHORITY = "https://your-authority.com"
OPENID_CONNECT_CLIENT_ID = "your_client_id"
OPENID_CONNECT_REDIRECT_URI = url_for('callback', _external=True)

@app.route('/login')
def login():
    """Redirect to the authorization endpoint"""
    params = {
        'client_id': OPENID_CONNECT_CLIENT_ID,
        'redirect_uri': OPENID_CONNECT_REDIRECT_URI,
        'response_type': 'code',
        'scope': 'openid profile email'
    }
    return redirect(f'{OPENID_CONNECT_AUTHORITY}/authorize?{request.args.urlencode(params)}')

@app.route('/callback')
def callback():
    """Callback from the authorization endpoint: exchange code for tokens"""
    code = request.args.get('code')
    if not code:
        flash("No authorization code received")
        return redirect(url_for('login'))

    # Request token
    params = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OPENID_CONNECT_REDIRECT_URI,
        'client_id': OPENID_CONNECT_CLIENT_ID
    }
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    response = requests.post(f'{OPENID_CONNECT_AUTHORITY}/token', data=params, headers=headers)
    if response.status_code != 200:
        flash("Failed to exchange code for tokens")
        return redirect(url_for('login'))

    # Get token
    token_response = response.json()
    access_token = token_response.get('access_token')
    if not access_token:
        flash("Failed to obtain access token")
        return redirect(url_for('login'))

    # Decode id_token and store user info in session
    params = {
        'id_token': access_token,
        'client_id': OPENID_CONNECT_CLIENT_ID
    }
    response = requests.post(f'{OPENID_CONNECT_AUTHORITY}/introspect', json=params)
    if response.status_code != 200:
        flash("Failed to introspect id_token")
        return redirect(url_for('login'))

    user_info = response.json().get('userinfo')
    session['username'] = user_info.get('preferred_username') or user_info.get('sub')
    return redirect('/protected')

@app.route('/protected')
def protected():
    """Return a simple page to verify that we're authenticated"""
    if 'username' in session:
        return f"Hello {session['username']}!"
    else:
        return "Not authenticated"

if __name__ == '__main__':
    app.run(debug=True)